"""
Parameterized generator for GH1210_wandb_11242.

Source PR:    https://github.com/wandb/wandb/pull/11242
Source Issue: N/A

Seed varies: renames 'activate' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1210_wandb_11242'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1210_wandb_11242'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('activate', 'activate' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1210_wandb_11242',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'wandb/wandb',
                "pr_number": 11242,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/wandb/wandb/pull/11242",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'CHANGELOG.unreleased.md': '# Unreleased changes\n\nAdd here any changes made in a PR that are relevant to end users. Allowed sections:\n\n- Added - for new features.\n- Changed - for changes in existing functionality.\n- Deprecated - for soon-to-be removed features.\n- Removed - for now removed features.\n- Fixed - for any bug fixes.\n- Security - in case of vulnerabilities.\n\nSection headings should be at level 3 (e.g. `### Added`).\n\n## Unreleased\n',
            'tests/system_tests/test_artifacts/test_wandb_artifacts_full.py': 'from __future__ import annotations\n\nimport os\nimport platform\nimport shutil\nimport time\nfrom datetime import datetime, timedelta, timezone\nfrom pathlib import Path\n\nimport numpy as np\nimport wandb\nfrom pytest import MonkeyPatch, mark, raises\nfrom pytest_mock import MockerFixture\nfrom wandb import Api, Artifact\nfrom wandb.errors import CommError\nfrom wandb.sdk.artifacts._internal_artifact import InternalArtifact\nfrom wandb.sdk.artifacts._validators import NAME_MAXLEN, RESERVED_ARTIFACT_TYPE_PREFIX\nfrom wandb.sdk.artifacts.artifact_file_cache import get_artifact_file_cache\nfrom wandb.sdk.artifacts.exceptions import ArtifactFinalizedError, WaitTimeoutError\nfrom wandb.sdk.lib.hashutil import md5_string\n\npytestmark = [\n    # requesting the `user` fixture sets API env var for ALL tests in this module\n    mark.usefixtures("user"),\n]\n\n\ndef test_add_table_from_dataframe():\n    import pandas as pd\n\n    df_float = pd.DataFrame([[1, 2.0, 3.0]], dtype=np.float64)\n    df_float32 = pd.DataFrame([[1, 2.0, 3.0]], dtype=np.float32)\n    df_bool = pd.DataFrame([[True, False, True]], dtype=np.bool_)\n\n    current_time = datetime.now()\n    df_timestamp = pd.DataFrame(\n        [[current_time + timedelta(days=i)] for i in range(10)], columns=["date"]\n    )\n\n    wb_table_float = wandb.Table(dataframe=df_float)\n    wb_table_float32 = wandb.Table(dataframe=df_float32)\n    wb_table_float32_recast = wandb.Table(dataframe=df_float32.astype(np.float64))\n    wb_table_bool = wandb.Table(dataframe=df_bool)\n    wb_table_timestamp = wandb.Table(dataframe=df_timestamp)\n\n    with wandb.init() as run:\n        artifact = Artifact("table-example", "dataset")\n        artifact.add(wb_table_float, "wb_table_float")\n        artifact.add(wb_table_float32_recast, "wb_table_float32_recast")\n        artifact.add(wb_table_float32, "wb_table_float32")\n        artifact.add(wb_table_bool, "wb_table_bool")\n\n        # check that timestamp is correctly converted to ms and not ns\n        json_repr = wb_table_timestamp.to_json(artifact)\n        assert "data" in json_repr and np.isclose(\n            json_repr["data"][0][0],\n            current_time.replace(tzinfo=timezone.utc).timestamp() * 1000,\n        )\n        artifact.add(wb_table_timestamp, "wb_table_timestamp")\n\n        run.log_artifact(artifact)\n\n\ndef test_artifact_error_for_invalid_aliases():\n    with wandb.init() as run:\n        artifact = Artifact("test-artifact", "dataset")\n        error_aliases = [["latest", "workflow:boom"], ["workflow/boom/test"]]\n        for aliases in error_aliases:\n            with raises(ValueError) as e_info:\n                run.log_artifact(artifact, aliases=aliases)\n            assert (\n                str(e_info.value)\n                == "Aliases must not contain any of the following characters: \'/\', \':\'"\n            )\n\n        for aliases in [["latest", "boom_test-q"]]:\n            run.log_artifact(artifact, aliases=aliases)\n\n\n@mark.parametrize(\n    "invalid_name",\n    (\n        "a" * (NAME_MAXLEN + 1),  # Name too long\n        "my/artifact",  # Invalid character(s)\n    ),\n)\ndef test_artifact_error_for_invalid_name(tmp_path: Path, api: Api, invalid_name: str):\n    """When logging a *file*, passing an invalid artifact name to `Run.log_artifact()` should raise an error."""\n    file_path = tmp_path / "test.txt"\n    file_path.write_text("test data")\n\n    # It should not be possible to log the artifact\n    with raises(ValueError):\n        with wandb.init() as run:\n            logged = run.log_artifact(file_path, name=invalid_name)\n            logged.wait()\n\n    # It should not be possible to retrieve the artifact either\n    with raises(CommError):\n        api.artifact(f"{invalid_name}:latest")\n\n\ndef test_artifact_upsert_no_id():\n    # NOTE: these tests are against a mock server so they are testing the internal flows, but\n    # not the actual data transfer.\n    artifact_name = f"distributed_artifact_{round(time.time())}"\n    artifact_type = "dataset"\n\n    # Upsert without a group or id should fail\n    with wandb.init() as run:\n        artifact = Artifact(name=artifact_name, type=artifact_type)\n        image = wandb.Image(np.random.randint(0, 255, (10, 10)))\n        artifact.add(image, "image_1")\n        with raises(TypeError):\n            run.upsert_artifact(artifact)\n\n\ndef test_artifact_upsert_group_id():\n    # NOTE: these tests are against a mock server so they are testing the internal flows, but\n    # not the actual data transfer.\n    artifact_name = f"distributed_artifact_{round(time.time())}"\n    group_name = f"test_group_{round(np.random.rand())}"\n    artifact_type = "dataset"\n\n    # Upsert with a group should succeed\n    with wandb.init(group=group_name) as run:\n        artifact = Artifact(name=artifact_name, type=artifact_type)\n        image = wandb.Image(np.random.randint(0, 255, (10, 10)))\n        artifact.add(image, "image_1")\n        run.upsert_artifact(artifact)\n\n\ndef test_artifact_upsert_distributed_id():\n    # NOTE: these tests are against a mock server so they are testing the internal flows, but\n    # not the actual data transfer.\n    artifact_name = f"distributed_artifact_{round(time.time())}"\n    group_name = f"test_group_{round(np.random.rand())}"\n    artifact_type = "dataset"\n\n    # Upsert with a distributed_id should succeed\n    with wandb.init() as run:\n        artifact = Artifact(name=artifact_name, type=artifact_type)\n        image = wandb.Image(np.random.randint(0, 255, (10, 10)))\n        artifact.add(image, "image_2")\n        run.upsert_artifact(artifact, distributed_id=group_name)\n\n\ndef test_artifact_finish_no_id():\n    # NOTE: these tests are against a mock server so they are testing the internal flows, but\n    # not the actual data transfer.\n    artifact_name = f"distributed_artifact_{round(time.time())}"\n    artifact_type = "dataset"\n\n    # Finish without a distributed_id should fail\n    with wandb.init() as run:\n        artifact = Artifact(artifact_name, type=artifact_type)\n        with raises(TypeError):\n            run.finish_artifact(artifact)\n\n\ndef test_artifact_finish_group_id():\n    # NOTE: these tests are against a mock server so they are testing the internal flows, but\n    # not the actual data transfer.\n    artifact_name = f"distributed_artifact_{round(time.time())}"\n    group_name = f"test_group_{round(np.random.rand())}"\n    artifact_type = "dataset"\n\n    # Finish with a distributed_id should succeed\n    with wandb.init(group=group_name) as run:\n        artifact = Artifact(artifact_name, type=artifact_type)\n        run.finish_artifact(artifact)\n\n\ndef test_artifact_finish_distributed_id():\n    # NOTE: these tests are against a mock server so they are testing the internal flows, but\n    # not the actual data transfer.\n    artifact_name = f"distributed_artifact_{round(time.time())}"\n    group_name = f"test_group_{round(np.random.rand())}"\n    artifact_type = "dataset"\n\n    # Finish with a distributed_id should succeed\n    with wandb.init() as run:\n        artifact = Artifact(artifact_name, type=artifact_type)\n        run.finish_artifact(artifact, distributed_id=group_name)\n\n\n@mark.parametrize("incremental", [False, True])\ndef test_add_file_respects_incremental(tmp_path: Path, api: Api, incremental: bool):\n    art_name = "incremental-test"\n    art_type = "dataset"\n\n    # Setup: create and log the original artifact\n    orig_filepath = tmp_path / "orig.txt"\n    orig_filepath.write_text("orig data")\n    with wandb.init() as orig_run:\n        orig_artifact = Artifact(art_name, art_type)\n        orig_artifact.add_file(str(orig_filepath))\n\n        orig_run.log_artifact(orig_artifact)\n\n    # Now add data from a new file to the same artifact, with or without `incremental=True`\n    new_filepath = tmp_path / "new.txt"\n    new_filepath.write_text("new data")\n    with wandb.init() as new_run:\n        new_artifact = Artifact(art_name, art_type, incremental=incremental)\n        new_artifact.add_file(str(new_filepath))\n\n        new_run.log_artifact(new_artifact)\n\n    # If `incremental=True` was used, expect both files in the artifact.  If not, expect only the last one.\n    final_artifact = api.artifact(f"{art_name}:latest")\n    final_manifest_entry_keys = final_artifact.manifest.entries.keys()\n    if incremental is True:\n        assert final_manifest_entry_keys == {orig_filepath.name, new_filepath.name}\n    else:\n        assert final_manifest_entry_keys == {new_filepath.name}\n\n\n@mark.flaky\n@mark.xfail(reason="flaky on CI")\ndef test_edit_after_add():\n    artifact = Artifact(name="hi-art", type="dataset")\n    filename = "file1.txt"\n    open(filename, "w").write("hello!")\n    artifact.add_file(filename)\n    open(filename, "w").write("goodbye.")\n    with wandb.init() as run:\n        run.log_artifact(artifact)\n        artifact.wait()\n    with wandb.init() as run:\n        art_path = run.use_artifact("hi-art:latest").download()\n\n    # The file from the retrieved artifact should match the original.\n    assert open(os.path.join(art_path, filename)).read() == "hello!"\n    # While the local file should have the edit applied.\n    assert open(filename).read() == "goodbye."\n\n\ndef test_remove_after_log():\n    with wandb.init() as run:\n        artifact = Artifact(name="hi-art", type="dataset")\n        artifact.add_reference(Path(__file__).as_uri())\n        run.log_artifact(artifact)\n        artifact.wait()\n\n    with wandb.init() as run:\n        retrieved = run.use_artifact("hi-art:latest")\n\n        with raises(ArtifactFinalizedError):\n            retrieved.remove("file1.txt")\n\n\n@mark.usefixtures("override_env_dirs")\n@mark.parametrize(\n    # Valid values for `skip_cache` in `Artifact.download()`\n    "skip_download_cache",\n    [None, False, True],\n)\ndef test_download_respects_skip_cache(tmp_path: Path, skip_download_cache: bool):\n    cache = get_artifact_file_cache()\n\n    artifact = Artifact(name="cache-test", type="dataset")\n    orig_content = "test123"\n    file_path = Path(tmp_path / "text.txt")\n    file_path.write_text(orig_content)\n\n    # Don\'t skip cache for setup\n    entry = artifact.add_file(file_path, policy="immutable", skip_cache=True)\n\n    with wandb.init() as run:\n        run.log_artifact(artifact)\n    artifact.wait()\n\n    # Ensure the uploaded file is in the cache.\n    cache_pathstr, hit, _ = cache.check_md5_obj_path(entry.digest, entry.size)\n    assert not hit\n\n    # Manually write a file into the cache path to check that it\'s:\n    # - used, if not skipping the cache (default behavior)\n    # - ignored, if skipping the cache\n    # This is kind of evil and might break if we later force cache validity.\n    replaced_cache_content = "corrupt"\n\n    cache_path = Path(cache_pathstr)\n    cache_path.parent.mkdir(parents=True, exist_ok=True)\n    cache_path.write_text(replaced_cache_content)\n\n    dest_dir = tmp_path / "download_root"\n    download_root = Path(artifact.download(dest_dir, skip_cache=skip_download_cache))\n    downloaded_content = (download_root / "text.txt").read_text()\n\n    if skip_download_cache in (None, False):\n        assert downloaded_content == replaced_cache_content\n        assert downloaded_content != orig_content\n    else:\n        assert downloaded_content != replaced_cache_content\n        assert downloaded_content == orig_content\n\n\n# Use a separate staging directory for the duration of this test.\n@mark.usefixtures("override_env_dirs")\ndef test_uploaded_artifacts_are_unstaged(temp_staging_dir: Path):\n    def dir_size(root: Path):\n        return sum(f.stat().st_size for f in root.rglob("*") if f.is_file())\n\n    data_path = Path("random.bin")\n    data_path.write_bytes(np.random.bytes(4096))\n\n    artifact = Artifact(name="stage-test", type="dataset")\n    artifact.add_file(str(data_path))\n\n    # The file is staged until it\'s finalized.\n    assert dir_size(temp_staging_dir) == 4096\n\n    with wandb.init() as run:\n        run.log_artifact(artifact)\n\n    # The staging directory should be empty again.\n    assert dir_size(temp_staging_dir) == 0\n\n\ndef test_large_manifests_passed_by_file(\n    monkeypatch: MonkeyPatch, mocker: MockerFixture\n):\n    writer_spy = mocker.spy(\n        wandb.sdk.interface.interface.InterfaceBase,\n        "_write_artifact_manifest_file",\n    )\n    monkeypatch.setattr(\n        wandb.sdk.interface.interface,\n        "MANIFEST_FILE_SIZE_THRESHOLD",\n        0,\n    )\n\n    content = "test content\\n"\n    with wandb.init() as run:\n        artifact = Artifact(name="large-manifest", type="dataset")\n        with artifact.new_file("test_file.txt") as f:\n            f.write(content)\n        artifact.manifest.entries["test_file.txt"].extra["test_key"] = {"x": 1}\n        run.log_artifact(artifact)\n        artifact.wait()\n\n    assert writer_spy.call_count == 1\n    file_written = writer_spy.spy_return\n    assert file_written is not None\n    # The file should have been cleaned up and deleted by the receiving process.\n    assert not os.path.exists(file_written)\n\n    with wandb.init() as run:\n        artifact = run.use_artifact("large-manifest:latest")\n        assert len(artifact.manifest) == 1\n        entry = artifact.manifest.entries.get("test_file.txt")\n        assert entry is not None\n        assert entry.digest == md5_string(content)\n        assert entry.size == len(content)\n        assert entry.ref is None\n        assert entry.extra["test_key"] == {"x": 1}\n\n\n# Use a separate staging directory for the duration of this test.\n@mark.usefixtures("override_env_dirs")\ndef test_mutable_uploads_with_cache_enabled(tmp_path: Path, temp_staging_dir: Path):\n    cache = get_artifact_file_cache()\n\n    data_path = Path(tmp_path / "random.txt")\n    data_path.write_text("test 123")\n    artifact = Artifact(name="stage-test", type="dataset")\n    manifest_entry = artifact.add_file(data_path)\n\n    # The file is staged\n    staging_files = list(temp_staging_dir.iterdir())\n    assert len(staging_files) == 1\n    assert staging_files[0].read_text() == "test 123"\n\n    with wandb.init() as run:\n        run.log_artifact(artifact)\n\n    # The file is cached\n    _, found, _ = cache.check_md5_obj_path(manifest_entry.digest, manifest_entry.size)\n    assert found\n\n    # The staged files are deleted after caching\n    staging_files = list(temp_staging_dir.iterdir())\n    assert len(staging_files) == 0\n\n\n# Use a separate staging directory for the duration of this test.\n@mark.usefixtures("override_env_dirs")\ndef test_mutable_uploads_with_cache_disabled(tmp_path: Path, temp_staging_dir: Path):\n    cache = get_artifact_file_cache()\n\n    data_path = Path(tmp_path / "random.txt")\n    data_path.write_text("test 123")\n    artifact = Artifact(name="stage-test", type="dataset")\n    manifest_entry = artifact.add_file(data_path, skip_cache=True)\n\n    # The file is staged\n    staging_files = list(temp_staging_dir.iterdir())\n    assert len(staging_files) == 1\n    assert staging_files[0].read_text() == "test 123"\n\n    with wandb.init() as run:\n        run.log_artifact(artifact)\n\n    # The file is not cached\n    _, found, _ = cache.check_md5_obj_path(manifest_entry.digest, manifest_entry.size)\n    assert not found\n\n    # The staged files are deleted even if caching is disabled\n    staging_files = list(temp_staging_dir.iterdir())\n    assert len(staging_files) == 0\n\n\n@mark.usefixtures("override_env_dirs")\ndef test_immutable_uploads_with_cache_enabled(tmp_path: Path, temp_staging_dir: Path):\n    cache = get_artifact_file_cache()\n\n    data_path = Path(tmp_path / "random.txt")\n    data_path.write_text("test 123")\n    artifact = Artifact(name="stage-test", type="dataset")\n    manifest_entry = artifact.add_file(data_path, policy="immutable")\n\n    # The file is not staged\n    staging_files = list(temp_staging_dir.iterdir())\n    assert len(staging_files) == 0\n\n    with wandb.init() as run:\n        run.log_artifact(artifact)\n\n    # The file is cached\n    _, found, _ = cache.check_md5_obj_path(manifest_entry.digest, manifest_entry.size)\n    assert found\n\n\n@mark.usefixtures("override_env_dirs")\ndef test_immutable_uploads_with_cache_disabled(tmp_path: Path, temp_staging_dir: Path):\n    cache = get_artifact_file_cache()\n\n    data_path = Path(tmp_path / "random.txt")\n    data_path.write_text("test 123")\n    artifact = Artifact(name="stage-test", type="dataset")\n    manifest_entry = artifact.add_file(data_path, skip_cache=True, policy="immutable")\n\n    # The file is not staged\n    staging_files = list(temp_staging_dir.iterdir())\n    assert len(staging_files) == 0\n\n    with wandb.init() as run:\n        run.log_artifact(artifact)\n\n    # The file is cached\n    _, found, _ = cache.check_md5_obj_path(manifest_entry.digest, manifest_entry.size)\n    assert not found\n\n\ndef test_local_references():\n    with wandb.init() as run:\n        t1 = wandb.Table(columns=[], data=[])\n        artifact1 = Artifact("test_local_references", "dataset")\n        artifact1.add(t1, "t1")\n        assert artifact1.manifest.entries["t1.table.json"].ref is None\n        run.log_artifact(artifact1)\n        artifact2 = Artifact("test_local_references_2", "dataset")\n        artifact2.add(t1, "t2")\n        assert artifact2.manifest.entries["t2.table.json"].ref is not None\n\n\ndef test_artifact_wait_success():\n    # Test artifact wait() timeout parameter\n    timeout = 60\n    leeway = 0.50\n    with wandb.init() as run:\n        artifact = Artifact("art", type="dataset")\n        start_timestamp = time.time()\n        run.log_artifact(artifact).wait(timeout=timeout)\n        elapsed_time = time.time() - start_timestamp\n        assert elapsed_time < timeout * (1 + leeway)\n\n\n@mark.parametrize("timeout", [0, 1e-6])\ndef test_artifact_wait_failure(timeout: float):\n    # Test to expect WaitTimeoutError when wait timeout is reached and large image\n    # wasn\'t uploaded yet\n    image = wandb.Image(np.random.randint(0, 255, (10, 10)))\n    with wandb.init() as run:\n        with raises(WaitTimeoutError):\n            artifact = Artifact("art", type="image")\n            artifact.add(image, "image")\n            run.log_artifact(artifact).wait(timeout=timeout)\n\n\n@mark.usefixtures("override_env_dirs")\ndef test_check_existing_artifact_before_download(\n    tmp_path: Path,\n    monkeypatch: MonkeyPatch,\n    temp_cache_dir: Path,\n):\n    """Don\'t re-download an artifact if it\'s already in the desired location."""\n    original_file = tmp_path / "test.txt"\n    original_file.write_text("hello")\n    with wandb.init() as run:\n        artifact = Artifact("art", type="dataset")\n        artifact.add_file(original_file)\n        run.log_artifact(artifact)\n\n    # Download the artifact\n    with wandb.init() as run:\n        artifact_path = run.use_artifact("art:latest").download()\n        assert os.path.exists(artifact_path)\n\n    # Delete the entire cache\n    shutil.rmtree(temp_cache_dir)\n\n    def fail_copy(src, dst):\n        raise RuntimeError(f"Should not be called, attempt to copy from {src} to {dst}")\n\n    # Monkeypatch the copy function to fail\n    monkeypatch.setattr(shutil, "copy2", fail_copy)\n\n    # Download the artifact again; it should be left in place despite the absent cache.\n    with wandb.init() as run:\n        artifact_path = Path(run.use_artifact("art:latest").download())\n        file1 = artifact_path / "test.txt"\n        assert file1.is_file()\n        assert file1.read_text() == "hello"\n\n\ndef test_check_changed_artifact_then_download(tmp_path: Path):\n    """*Do* re-download an artifact if it\'s been modified in place."""\n    original_file = tmp_path / "test.txt"\n    original_file.write_text("hello")\n    with wandb.init() as run:\n        artifact = Artifact("art", type="dataset")\n        artifact.add_file(original_file)\n        run.log_artifact(artifact)\n\n    # Download the artifact\n    with wandb.init() as run:\n        artifact_path = Path(run.use_artifact("art:latest").download())\n        file1 = artifact_path / "test.txt"\n        assert file1.is_file()\n        assert file1.read_text() == "hello"\n\n    # Modify the artifact file to change its hash.\n    file1.write_text("goodbye")\n\n    # Download it again; it should be replaced with the original version.\n    with wandb.init() as run:\n        artifact_path = Path(run.use_artifact("art:latest").download())\n        file2 = artifact_path / "test.txt"\n        assert file1 == file2  # Same path, but the content should have changed.\n        assert file2.is_file()\n        assert file2.read_text() == "hello"\n\n\n@mark.parametrize("path_type", [str, Path])\ndef test_log_dir_directly(example_files: Path, path_type: type[str | Path]):\n    with wandb.init() as run:\n        run_id = run.id\n        artifact = run.log_artifact(path_type(example_files))\n    artifact.wait()\n\n    assert artifact is not None\n    assert artifact.id is not None  # It was successfully logged.\n    assert artifact.name == f"run-{run_id}-{Path(example_files).name}:v0"\n\n\n@mark.parametrize("path_type", [str, Path])\ndef test_log_file_directly(example_file: Path, path_type: type[str | Path]):\n    with wandb.init() as run:\n        run_id = run.id\n        artifact = run.log_artifact(path_type(example_file))\n    artifact.wait()\n\n    assert artifact is not None\n    assert artifact.id is not None\n    assert artifact.name == f"run-{run_id}-{Path(example_file).name}:v0"\n\n\ndef test_log_reference_directly(example_files: Path):\n    with wandb.init() as run:\n        run_id = run.id\n        artifact = run.log_artifact(example_files.resolve().as_uri())\n    artifact.wait()\n\n    assert artifact is not None\n    assert artifact.id is not None\n    assert artifact.name == f"run-{run_id}-{example_files.name}:v0"\n\n\n@mark.usefixtures("override_env_dirs")\ndef test_artifact_download_root(logged_artifact: Artifact, temp_artifact_dir: Path):\n    name_path = logged_artifact.name\n    if platform.system() == "Windows":\n        name_path = name_path.replace(":", "-")\n\n    downloaded = Path(logged_artifact.download())\n    assert downloaded == temp_artifact_dir / name_path\n\n\ndef test_log_and_download_with_path_prefix(tmp_path: Path):\n    artifact = Artifact(name="test-artifact", type="dataset")\n    file_paths = [\n        tmp_path / "some-prefix" / "one.txt",\n        tmp_path / "some-prefix-two.txt",\n        tmp_path / "other-thing.txt",\n    ]\n\n    # Create files and add them to the artifact\n    for file_path in file_paths:\n        file_path.parent.mkdir(parents=True, exist_ok=True)\n        file_path.write_text(f"Content of {file_path.name}")\n    artifact.add_dir(tmp_path)\n\n    with wandb.init() as run:\n        run.log_artifact(artifact)\n\n    with wandb.init() as run:\n        logged_artifact = run.use_artifact("test-artifact:latest")\n        download_dir = Path(logged_artifact.download(path_prefix="some-prefix"))\n\n    # Check that the files with the prefix are downloaded\n    assert (download_dir / "some-prefix" / "one.txt").is_file()\n    assert (download_dir / "some-prefix-two.txt").is_file()\n\n    # Check that the file without the prefix is not downloaded\n    assert not (download_dir / "other-thing.txt").exists()\n    shutil.rmtree(download_dir)\n\n    with wandb.init() as run:\n        logged_artifact = run.use_artifact("test-artifact:latest")\n        download_dir = Path(logged_artifact.download(path_prefix="some-prefix/"))\n\n    # Only the file in the exact subdirectory should download.\n    assert (download_dir / "some-prefix" / "one.txt").is_file()\n    assert not (download_dir / "some-prefix-two.txt").exists()\n    assert not (download_dir / "other-thing.txt").exists()\n\n    shutil.rmtree(download_dir)\n\n    with wandb.init() as run:\n        logged_artifact = run.use_artifact("test-artifact:latest")\n        download_dir = Path(logged_artifact.download(path_prefix=""))\n\n    # All files should download.\n    assert (download_dir / "some-prefix" / "one.txt").is_file()\n    assert (download_dir / "some-prefix-two.txt").is_file()\n    assert (download_dir / "other-thing.txt").is_file()\n\n\ndef test_retrieve_missing_artifact(logged_artifact: Artifact, api: Api):\n    with raises(CommError, match="project \'bar\' not found"):\n        api.artifact(f"foo/bar/{logged_artifact.name}")\n\n    with raises(CommError, match="project \'bar\' not found"):\n        api.artifact(f"{logged_artifact.entity}/bar/{logged_artifact.name}")\n\n    with raises(CommError):\n        api.artifact(f"{logged_artifact.entity}/{logged_artifact.project}/baz")\n\n    with raises(CommError):\n        api.artifact(f"{logged_artifact.entity}/{logged_artifact.project}/baz:v0")\n\n\ndef test_new_draft(api: Api):\n    art = Artifact("test-artifact", "test-type")\n    with art.new_file("boom.txt", "w") as f:\n        f.write("detonation")\n\n    # Set properties that won\'t be copied.\n    art.ttl = None\n\n    project = "test"\n    with wandb.init(project=project) as run:\n        run.log_artifact(art, aliases=["a"])\n        run.link_artifact(art, f"{project}/my-sample-portfolio")\n\n    parent = api.artifact(f"{project}/my-sample-portfolio:latest")\n    draft = parent.new_draft()\n\n    # entity/project/name should all match the *source* artifact.\n    assert draft.type == art.type\n    assert draft.name == "test-artifact"  # No version suffix.\n    assert draft._base_id == parent.id  # Parent is the source artifact.\n\n    # We would use public properties, but they\'re only available on non-draft artifacts.\n    assert draft._entity == parent.entity\n    assert draft._project == parent.project\n    assert draft._source_name == art.name.split(":")[0]\n    assert draft._source_entity == parent.entity\n    assert draft._source_project == parent.project\n\n    # The draft won\'t have fields that only exist after being committed.\n    assert draft._version is None\n    assert draft._source_version is None\n    assert draft._ttl_duration_seconds is None\n    assert draft._ttl_is_inherited\n    assert not draft._ttl_changed\n    assert draft._aliases == []\n    assert draft._saved_aliases == []\n    assert draft.is_draft()\n    assert draft._created_at is None\n    assert draft._updated_at is None\n    assert not draft._final\n\n    # Add a file and log the new draft.\n    with draft.new_file("bang.txt", "w") as f:\n        f.write("expansion")\n\n    with wandb.init(project=project) as run:\n        run.log_artifact(draft)\n\n    child = api.artifact(f"{project}/test-artifact:latest")\n    assert child.version == "v1"\n\n    assert len(child.manifest.entries) == 2\n    file_path = child.download()\n    assert os.path.exists(os.path.join(file_path, "boom.txt"))\n    assert os.path.exists(os.path.join(file_path, "bang.txt"))\n\n\ndef test_get_artifact_collection(logged_artifact: Artifact):\n    collection = logged_artifact.collection\n    assert logged_artifact.entity == collection.entity\n    assert logged_artifact.project == collection.project\n    assert logged_artifact.name.startswith(collection.name)\n    assert logged_artifact.type == collection.type\n\n\ndef test_used_artifacts_preserve_original_project(\n    user: str,\n    api: Api,\n    logged_artifact: Artifact,\n):\n    """Run artifacts from the API should preserve the original project they were created in."""\n    orig_project = logged_artifact.project  # Original project that created the artifact\n    new_project = "new-project"  # New project using the same artifact\n\n    artifact_path = f"{user}/{orig_project}/{logged_artifact.name}"\n\n    # Use the artifact within a *different* project\n    with wandb.init(entity=user, project=new_project) as run:\n        art = run.use_artifact(artifact_path)\n        art.download()\n\n    # Check project of artifact vs run as retrieved from the API\n    run_from_api = api.run(run.path)\n    art_from_run = run_from_api.used_artifacts()[0]\n\n    # Assumption check in case of future changes to fixtures\n    assert orig_project != new_project\n\n    assert run_from_api.project == new_project\n    assert art_from_run.project == orig_project\n\n\ndef test_internal_artifacts():\n    internal_type = f"{RESERVED_ARTIFACT_TYPE_PREFIX}invalid"\n    with wandb.init() as run:\n        with raises(ValueError, match="is reserved for internal use"):\n            artifact = Artifact(name="test-artifact", type=internal_type)\n\n        artifact = InternalArtifact(name="test-artifact", type=internal_type)\n        run.log_artifact(artifact)\n\n\ndef test_storage_policy_storage_region(user: str, api: Api, tmp_path: Path):\n    file_path = tmp_path / "test.txt"\n    file_path.write_text("test data")\n    project = "test"\n    with wandb.init(entity=user, project=project) as run:\n        # Set in onprem/local/scripts/env.txt when building the test container from gorilla.\n        art = Artifact(\n            "test-storage-region", type="dataset", storage_region="minio-local"\n        )\n        art.add_file(file_path)\n        run.log_artifact(art)\n        art.wait()\n\n    # Able to download the file\n    art = api.artifact(f"{user}/{project}/test-storage-region:latest")\n    art.download()\n    assert os.path.exists(file_path)\n    assert open(file_path).read() == "test data"\n\n    # Manifest should have the storage region\n    manifest = art.manifest.to_manifest_json()\n    assert manifest["storagePolicyConfig"]["storageRegion"] == "minio-local"\n\n\ndef test_storage_policy_storage_region_not_available():\n    with wandb.init() as run:\n        # NOTE: We match on the region name instead of exact API error because different versions of server fails at different APIs.\n        # In latest version, storageRegion is passed in `CreateArtifact` and it would return soemthing like `CreateArtifact invalid storageRegion: coreweave-us`\n        # In previous version, storageRegion is ignored in graphql APIs but used in `CommitArtifact` from manifest json and ther error is `malformed region: coreweave-us`\n        with raises(ValueError, match="coreweave-us"):\n            art = Artifact("test", type="dataset", storage_region="coreweave-us")\n            run.log_artifact(art)\n            art.wait()\n',
            'tests/unit_tests/test_artifacts/test_wandb_artifacts.py': 'import functools\nimport queue\nimport shutil\nimport unittest.mock as mock\nfrom concurrent.futures import ThreadPoolExecutor\nfrom contextlib import contextmanager\nfrom pathlib import Path\nfrom string import ascii_letters, digits\nfrom typing import IO, TYPE_CHECKING, Any, AnyStr, ContextManager, Mapping, Optional\nfrom unittest.mock import Mock\n\nimport pytest\nimport requests\nfrom hypothesis import given\nfrom hypothesis.strategies import from_regex, text\nfrom wandb.filesync.step_prepare import ResponsePrepare, StepPrepare\nfrom wandb.sdk.artifacts._validators import NAME_MAXLEN\nfrom wandb.sdk.artifacts.artifact import Artifact\nfrom wandb.sdk.artifacts.artifact_file_cache import ArtifactFileCache\nfrom wandb.sdk.artifacts.artifact_instance_cache import artifact_instance_cache\nfrom wandb.sdk.artifacts.artifact_manifest_entry import ArtifactManifestEntry\nfrom wandb.sdk.artifacts.artifact_state import ArtifactState\nfrom wandb.sdk.artifacts.exceptions import ArtifactNotLoggedError\nfrom wandb.sdk.artifacts.storage_policies._multipart import (\n    multipart_download,\n    should_multipart_download,\n)\nfrom wandb.sdk.artifacts.storage_policies.wandb_storage_policy import WandbStoragePolicy\n\nif TYPE_CHECKING:\n    from typing import Protocol\n\n    from wandb.sdk.internal.internal_api import CreateArtifactFileSpecInput\n\n    class StoreFileFixture(Protocol):\n        def __call__(\n            self,\n            policy: WandbStoragePolicy,\n            artifact_id: str,\n            artifact_manifest_id: str,\n            entry_path: str,\n            entry_digest: str,\n            entry_local_path: Optional[Path] = None,\n            preparer: Optional[StepPrepare] = None,\n        ) -> bool:\n            pass\n\n\ndef is_cache_hit(cache: ArtifactFileCache, digest: str, size: int) -> bool:\n    _, hit, _ = cache.check_md5_obj_path(digest, size)\n    return hit\n\n\ndef singleton_queue(x):\n    q = queue.Queue()\n    q.put(x)\n    return q\n\n\ndef dummy_response_prepare(spec):\n    name = spec["name"]\n    return ResponsePrepare(\n        birth_artifact_id=f"artifact-id-{name}",\n        upload_url=f"http://wandb-test/upload-url-{name}",\n        upload_headers=["x-my-header-key:my-header-val"],\n        upload_id=None,\n        storage_path="wandb_artifact/123456789",\n        multipart_upload_urls=None,\n    )\n\n\ndef mock_prepare(spec: "CreateArtifactFileSpecInput") -> ResponsePrepare:\n    return singleton_queue(dummy_response_prepare(spec))\n\n\ndef mock_preparer(**kwargs):\n    kwargs.setdefault("prepare", Mock(wraps=mock_prepare))\n    return Mock(**kwargs)\n\n\ndef test_capped_cache():\n    for i in range(101):\n        art = Artifact(f"foo-{i}", type="test")\n        art._id = f"foo-{i}"\n        art._state = "COMMITTED"\n        artifact_instance_cache[art.id] = art\n    assert len(artifact_instance_cache) == 100\n\n\nclass TestStoreFile:\n    @staticmethod\n    def _fixture_kwargs_to_kwargs(\n        artifact_id: str = "my-artifact-id",\n        artifact_manifest_id: str = "my-artifact-manifest-id",\n        entry_path: str = "my-path",\n        entry_digest: str = "my-digest",\n        entry_local_path: Optional[Path] = None,\n        preparer: Optional[StepPrepare] = None,\n    ) -> Mapping[str, Any]:\n        if preparer is None:\n            preparer = mock_preparer()\n        return dict(\n            artifact_id=artifact_id,\n            artifact_manifest_id=artifact_manifest_id,\n            entry=ArtifactManifestEntry(\n                path=entry_path,\n                digest=entry_digest,\n                local_path=entry_local_path,\n            ),\n            preparer=preparer if preparer else mock_preparer(),\n        )\n\n    @staticmethod\n    def _store_file(policy: WandbStoragePolicy, **kwargs) -> bool:\n        """Runs store_file to completion."""\n        return policy.store_file(**TestStoreFile._fixture_kwargs_to_kwargs(**kwargs))\n\n    @pytest.fixture(params=["sync", "async"])\n    def store_file_mode(self, request) -> str:\n        return request.param\n\n    @pytest.fixture\n    def store_file(self) -> "StoreFileFixture":\n        """Fixture to run prepare and return the result.\n\n        Example usage:\n\n            def test_smoke(store_file: "StoreFileFixture", api):\n                store_file(WandbStoragePolicy(api=api), entry_local_path=example_file)\n                api.upload_file_retry.assert_called_once()\n        """\n        return TestStoreFile._store_file\n\n    @pytest.fixture\n    def api(self):\n        """Fixture to give a mock `internal_api.Api` object, with properly-functioning upload methods."""\n        upload_file_retry = Mock()\n        upload_multipart_file_chunk_retry = Mock()\n        complete_multipart_upload_artifact = Mock()\n\n        return Mock(\n            upload_file_retry=upload_file_retry,\n            upload_multipart_file_chunk_retry=upload_multipart_file_chunk_retry,\n            complete_multipart_upload_artifact=complete_multipart_upload_artifact,\n        )\n\n    def test_smoke(self, store_file: "StoreFileFixture", api, example_file: Path):\n        store_file(WandbStoragePolicy(api=api), entry_local_path=example_file)\n        api.upload_file_retry.assert_called_once()\n\n    def test_uploads_to_prepared_url(\n        self, store_file: "StoreFileFixture", api, example_file: Path\n    ):\n        preparer = mock_preparer(\n            prepare=lambda spec: singleton_queue(\n                dummy_response_prepare(spec)._replace(\n                    upload_url="https://wandb-test/dst"\n                )\n            )\n        )\n        store_file(\n            WandbStoragePolicy(api=api),\n            entry_local_path=example_file,\n            preparer=preparer,\n        )\n        assert api.upload_file_retry.call_args[0][0] == "https://wandb-test/dst"\n\n    def test_passes_prepared_headers_to_upload(\n        self, store_file: "StoreFileFixture", api, example_file: Path\n    ):\n        preparer = mock_preparer(\n            prepare=lambda spec: singleton_queue(\n                dummy_response_prepare(spec)._replace(\n                    upload_headers=["x-my-header:my-header-val"]\n                )\n            )\n        )\n        store_file(\n            WandbStoragePolicy(api=api),\n            entry_local_path=example_file,\n            preparer=preparer,\n        )\n        assert api.upload_file_retry.call_args[1]["extra_headers"] == {\n            "x-my-header": "my-header-val"\n        }\n\n    @pytest.mark.parametrize(\n        ["upload_url", "expect_upload", "expect_deduped"],\n        [\n            ("http://wandb-test/dst", True, False),\n            (None, False, True),\n        ],\n    )\n    def test_skips_upload_if_no_prepared_url(\n        self,\n        store_file: "StoreFileFixture",\n        api,\n        example_file: Path,\n        upload_url: Optional[str],\n        expect_upload: bool,\n        expect_deduped: bool,\n    ):\n        preparer = mock_preparer(\n            prepare=lambda spec: singleton_queue(\n                dummy_response_prepare(spec)._replace(upload_url=upload_url)\n            )\n        )\n        policy = WandbStoragePolicy(api=api)\n\n        deduped = store_file(policy, entry_local_path=example_file, preparer=preparer)\n        assert deduped == expect_deduped\n\n        if expect_upload:\n            api.upload_file_retry.assert_called_once()\n        else:\n            api.upload_file_retry.assert_not_called()\n\n    @pytest.mark.parametrize(\n        ["has_local_path", "expect_upload"],\n        [\n            (True, True),\n            (False, False),\n        ],\n    )\n    def test_skips_upload_if_no_local_path(\n        self,\n        store_file: "StoreFileFixture",\n        api,\n        example_file: Path,\n        has_local_path: bool,\n        expect_upload: bool,\n    ):\n        policy = WandbStoragePolicy(api=api)\n\n        deduped = store_file(\n            policy,\n            entry_local_path=example_file if has_local_path else None,\n        )\n        assert not deduped\n\n        if expect_upload:\n            api.upload_file_retry.assert_called_once()\n        else:\n            api.upload_file_retry.assert_not_called()\n\n    @pytest.mark.parametrize("err", [None, Exception("some error")])\n    def test_caches_result_on_success(\n        self,\n        store_file: "StoreFileFixture",\n        api,\n        example_file: Path,\n        artifact_file_cache: ArtifactFileCache,\n        err: Optional[Exception],\n    ):\n        size = example_file.stat().st_size\n\n        api.upload_file_retry = Mock(side_effect=err)\n        policy = WandbStoragePolicy(api=api, cache=artifact_file_cache)\n\n        assert not is_cache_hit(artifact_file_cache, "my-digest", size)\n\n        store = functools.partial(store_file, policy, entry_local_path=example_file)\n\n        if err is None:\n            store()\n            assert is_cache_hit(artifact_file_cache, "my-digest", size)\n        else:\n            with pytest.raises(Exception, match=err.args[0]):\n                store()\n            assert not is_cache_hit(artifact_file_cache, "my-digest", size)\n\n    @pytest.mark.parametrize(\n        [\n            "upload_url",\n            "multipart_upload_urls",\n            "expect_single_upload",\n            "expect_multipart_upload",\n            "expect_deduped",\n        ],\n        [\n            (\n                "http://wandb-test/dst",\n                {\n                    1: "http://wandb-test/part=1",\n                    2: "http://wandb-test/part=2",\n                    3: "http://wandb-test/part=3",\n                },\n                False,\n                True,\n                False,\n            ),\n            (\n                None,\n                {\n                    1: "http://wandb-test/part=1",\n                    2: "http://wandb-test/part=2",\n                    3: "http://wandb-test/part=3",\n                },\n                False,\n                False,\n                True,\n            ),  # super weird case but shouldn\'t happen, upload url should always be generated\n            ("http://wandb-test/dst", None, True, False, False),\n            (None, None, False, False, True),\n        ],\n    )\n    @mock.patch(\n        "wandb.sdk.artifacts.storage_policies.wandb_storage_policy.WandbStoragePolicy."\n        "s3_multipart_file_upload"\n    )\n    def test_multipart_upload_handle_response(\n        self,\n        mock_s3_multipart_file_upload,\n        api,\n        example_file: Path,\n        upload_url: Optional[str],\n        multipart_upload_urls: Optional[dict],\n        expect_multipart_upload: bool,\n        expect_single_upload: bool,\n        expect_deduped: bool,\n    ):\n        # Tests if we handle uploading correctly depending on what response we get from CreateArtifactFile.\n        preparer = mock_preparer(\n            prepare=lambda spec: singleton_queue(\n                dummy_response_prepare(spec)._replace(\n                    upload_url=upload_url, multipart_upload_urls=multipart_upload_urls\n                )\n            )\n        )\n        policy = WandbStoragePolicy(api=api)\n        # Mock minimum size for multipart so that we can test multipart\n        with mock.patch(\n            "wandb.sdk.artifacts.storage_policies._multipart.MIN_MULTI_UPLOAD_SIZE",\n            example_file.stat().st_size,\n        ):\n            deduped = self._store_file(\n                policy, entry_local_path=example_file, preparer=preparer\n            )\n            assert deduped == expect_deduped\n\n            if expect_multipart_upload:\n                mock_s3_multipart_file_upload.assert_called_once()\n                api.complete_multipart_upload_artifact.assert_called_once()\n                api.upload_file_retry.assert_not_called()\n            elif expect_single_upload:\n                api.upload_file_retry.assert_called_once()\n                api.upload_multipart_file_chunk_retry.assert_not_called()\n            else:\n                api.upload_file_retry.assert_not_called()\n                api.upload_multipart_file_chunk_retry.assert_not_called()\n\n    def test_s3_multipart_file_upload(\n        self,\n        api,\n        example_file: Path,\n    ):\n        # Tests that s3 multipart calls upload on every part and retrieves the etag for every part\n        multipart_parts = {\n            1: "http://wandb-test/part=1",\n            2: "http://wandb-test/part=2",\n            3: "http://wandb-test/part=3",\n        }\n        hex_digests = {1: "abc1", 2: "abc2", 3: "abc3"}\n        chunk_size = 1\n        policy = WandbStoragePolicy(api=api)\n        responses = []\n        for idx in range(1, len(hex_digests) + 1):\n            etag_response = requests.Response()\n            etag_response.headers = {"ETag": hex_digests[idx]}\n            responses.append(etag_response)\n        api.upload_multipart_file_chunk_retry.side_effect = responses\n\n        with mock.patch("builtins.open", mock.mock_open(read_data="abc")):\n            etags = policy.s3_multipart_file_upload(\n                example_file, chunk_size, hex_digests, multipart_parts, extra_headers={}\n            )\n            assert api.upload_multipart_file_chunk_retry.call_count == 3\n            # Note Etags == hex_digest when there isn\'t an additional encryption method for uploading.\n            assert len(etags) == len(hex_digests)\n            for etag in etags:\n                assert etag["hexMD5"] == hex_digests[etag["partNumber"]]\n\n\n@pytest.mark.parametrize("invalid_type", ["job", "wandb-history", "wandb-foo"])\ndef test_invalid_artifact_type(invalid_type):\n    with pytest.raises(ValueError, match="reserved for internal use"):\n        Artifact("foo", type=invalid_type)\n\n\n@given(\n    invalid_name=(\n        text(  # Too many characters\n            alphabet={*ascii_letters, *digits, "_", "-", " "},\n            min_size=NAME_MAXLEN + 1,\n        )\n        | from_regex(  # Contains invalid characters\n            r"(\\w|\\d|\\s)*(/)(\\w|\\d|\\s)*",\n            fullmatch=True,\n        )\n    )\n)\ndef test_invalid_artifact_name(invalid_name):\n    """Prevent users from instantiating an artifact with an invalid name."""\n    with pytest.raises(ValueError):\n        _ = Artifact(invalid_name, type="any")\n\n\n@pytest.mark.parametrize(\n    "property",\n    [\n        "entity",\n        "project",\n        "version",\n        "source_entity",\n        "source_project",\n        "source_version",\n        "ttl",\n        "aliases",  # Perhaps shouldn\'t be restricted? It is today.\n        "commit_hash",\n        "file_count",  # Probably doesn\'t need to be restricted, but is today.\n        "created_at",\n        "updated_at",\n    ],\n)\ndef test_unlogged_artifact_property_errors(property):\n    art = Artifact("foo", type="any")\n    error_message = f"\'Artifact.{property}\' used prior to logging artifact"\n    with pytest.raises(ArtifactNotLoggedError, match=error_message):\n        getattr(art, property)\n\n\n@pytest.mark.parametrize(\n    "method",\n    [\n        "new_draft",\n        "download",\n        "checkout",\n        "verify",\n        "file",\n        "files",\n        "delete",\n        "used_by",\n        "logged_by",\n        "json_encode",\n    ],\n)\ndef test_unlogged_artifact_basic_method_errors(method):\n    art = Artifact("foo", type="any")\n    error_message = f"\'Artifact.{method}\' used prior to logging artifact"\n    with pytest.raises(ArtifactNotLoggedError, match=error_message):\n        getattr(art, method)()\n\n\ndef test_unlogged_artifact_other_method_errors():\n    art = Artifact("foo", type="any")\n    with pytest.raises(ArtifactNotLoggedError, match="Artifact.get_entry"):\n        art.get_entry("pathname")\n\n    with pytest.raises(ArtifactNotLoggedError, match="Artifact.get"):\n        art["obj_name"]\n\n\ndef test_cache_write_failure_is_ignored(monkeypatch, capsys):\n    def bad_write(*args, **kwargs):\n        raise FileNotFoundError("unable to copy from source file")\n\n    monkeypatch.setattr(shutil, "copyfileobj", bad_write)\n    policy = WandbStoragePolicy()\n    path = Path("foo.txt")\n    path.write_text("hello")\n\n    entry = ArtifactManifestEntry(\n        path=path,\n        digest="NWQ0MTQwMmFiYzRiMmE3NmI5NzE5ZDkxMTAxN2M1OTI=",\n        local_path=path,\n    )\n\n    policy._write_cache(entry)\n\n    captured = capsys.readouterr()\n    assert "Failed to cache" in captured.err\n\n\ndef test_artifact_manifest_length():\n    artifact = Artifact("test-artifact", "test-type")\n    assert len(artifact.manifest) == 0\n    with artifact.new_file("test.txt") as f:\n        f.write("test")\n    assert len(artifact.manifest) == 1\n\n    testpath = Path("test.txt")\n    testpath.write_text("also a test")\n    artifact.add_reference(testpath.resolve().as_uri(), "test2.txt")\n    assert len(artifact.manifest) == 2\n\n\ndef test_download_with_pathlib_root(monkeypatch):\n    artifact = Artifact("test-artifact", "test-type")\n    artifact._state = ArtifactState.COMMITTED\n    monkeypatch.setattr(artifact, "_download", lambda *args, **kwargs: "")\n    monkeypatch.setattr(artifact, "_download_using_core", lambda *args, **kwargs: "")\n    custom_path = Path("some/relative/path")\n    artifact.download(custom_path)\n    assert len(artifact._download_roots) == 1\n    root = list(artifact._download_roots)[0]\n    path_parts = custom_path.parts\n    assert Path(root).parts[-len(path_parts) :] == path_parts\n\n\ndef test_artifact_multipart_download_threshold():\n    mb = 1024 * 1024\n    assert should_multipart_download(100 * mb) is False\n    assert should_multipart_download(100 * mb, override=True) is True\n    assert should_multipart_download(100 * mb, override=False) is False\n\n    assert should_multipart_download(2080 * mb) is True\n    assert should_multipart_download(2080 * mb, override=True) is True\n    assert should_multipart_download(2080 * mb, override=False) is False\n\n    assert should_multipart_download(5070 * mb) is True\n    assert should_multipart_download(5070 * mb, override=True) is True\n    assert should_multipart_download(5070 * mb, override=False) is False\n\n\nclass MockOpener:\n    """Wrap a file as a Opener."""\n\n    def __init__(self, file: IO):\n        self.file = file\n\n    def __call__(self, mode: str = "r") -> ContextManager[IO]:\n        @contextmanager\n        def _fake_context():\n            yield self.file\n\n        return _fake_context()\n\n\ndef test_artifact_multipart_download_network_error():\n    # Disable retries and backoff to avoid timeout in test\n    session = requests.Session()\n    adapter = requests.adapters.HTTPAdapter(max_retries=0)\n    session.mount("http://", adapter)\n    session.mount("https://", adapter)\n\n    class CountOnlyFile(IO):\n        def __init__(self):\n            self.write_count = 0\n            self.seek_count = 0\n\n        def seek(self, offset: int, whence: int = 0) -> int:\n            self.seek_count += 1\n            return offset\n\n        def write(self, s: AnyStr) -> int:\n            self.write_count += 1\n            return len(s)\n\n    file = CountOnlyFile()\n    opener = MockOpener(file)\n    with pytest.raises(requests.exceptions.ConnectionError):\n        with ThreadPoolExecutor(max_workers=2) as executor:\n            multipart_download(\n                executor, session, "https://invalid.com", 4 * 1024 * 1024 * 1024, opener\n            )\n    assert file.seek_count == 0\n    assert file.write_count == 0\n\n\ndef test_artifact_multipart_download_disk_error():\n    class ThrowFile(IO):\n        def seek(self, offset: int, whence: int = 0) -> int:\n            raise ValueError("I/O operation on closed file")\n\n    class MockResponse:\n        def raise_for_status(self):\n            pass\n\n        def iter_content(self, chunk_size: int = 1024):\n            return [b"test"]\n\n        def __enter__(self):\n            return self\n\n        def __exit__(self, exc_type, exc_value, traceback):\n            pass\n\n    class MockSession:\n        def __init__(self):\n            self.get_count = 0\n\n        def get(self, url: str, stream: bool = False, headers: dict = None):\n            self.get_count += 1\n            return MockResponse()\n\n    session = MockSession()\n\n    file = ThrowFile()\n    opener = MockOpener(file)\n    with pytest.raises(ValueError):\n        with ThreadPoolExecutor(max_workers=2) as executor:\n            multipart_download(\n                executor,\n                session,\n                "https://mocked.com",\n                500 * 1024 * 1024,  # 500MB should have 5 parts\n                opener,\n            )\n    # After first get call has errors, reamining get call should return without making the call.\n    # It can be 5 depends on underlying environment,e.g. it fails on winodws from time to time.\n    assert session.get_count <= 5\n',
            'wandb/sdk/artifacts/storage_policies/_factories.py': 'from __future__ import annotations\n\nfrom typing import TYPE_CHECKING, Final\n\nfrom ..storage_handler import StorageHandler\nfrom ..storage_handlers.azure_handler import AzureHandler\nfrom ..storage_handlers.gcs_handler import GCSHandler\nfrom ..storage_handlers.http_handler import HTTPHandler\nfrom ..storage_handlers.local_file_handler import LocalFileHandler\nfrom ..storage_handlers.s3_handler import S3Handler\nfrom ..storage_handlers.wb_artifact_handler import WBArtifactHandler\nfrom ..storage_handlers.wb_local_artifact_handler import WBLocalArtifactHandler\n\nif TYPE_CHECKING:\n    from requests import Response, Session\n\n\nHTTP_POOL_CONNECTIONS: Final[int] = 64\nHTTP_POOL_MAXSIZE: Final[int] = 64\n\n\ndef raise_for_status(response: Response, *_, **__) -> None:\n    """A `requests.Session` hook to raise for status on all requests."""\n    response.raise_for_status()\n\n\ndef make_http_session() -> Session:\n    """Return a `requests.Session` configured for artifact storage handlers."""\n    from requests import Session\n    from requests.adapters import HTTPAdapter\n    from urllib3.util.retry import Retry\n\n    from wandb.sdk import wandb_setup\n\n    # Sleep length: 0, 2, 4, 8, 16, 32, 64, 120, 120, 120, 120, 120, 120, 120, 120, 120\n    # seconds, i.e. a total of 20min 6s.\n    HTTP_RETRY_STRATEGY: Final[Retry] = Retry(  # noqa: N806\n        backoff_factor=1,\n        total=16,\n        status_forcelist=(308, 408, 409, 429, 500, 502, 503, 504),\n    )\n\n    session = Session()\n    # Use the global settings singleton which already includes env var updates.\n    settings = wandb_setup.singleton().settings\n    headers = settings.x_extra_http_headers or {}\n    session.headers.update(headers)\n\n    # Explicitly configure the retry strategy for http/https adapters.\n    adapter = HTTPAdapter(\n        max_retries=HTTP_RETRY_STRATEGY,\n        pool_connections=HTTP_POOL_CONNECTIONS,\n        pool_maxsize=HTTP_POOL_MAXSIZE,\n    )\n    session.mount("http://", adapter)\n    session.mount("https://", adapter)\n\n    # Always raise on HTTP status errors.\n    session.hooks["response"].append(raise_for_status)\n    return session\n\n\ndef make_storage_handlers(session: Session) -> list[StorageHandler]:\n    """A factory that returns the default artifact storage handlers."""\n    return [\n        S3Handler(),  # s3\n        GCSHandler(),  # gcs\n        AzureHandler(),  # azure\n        HTTPHandler(session, scheme="http"),  # http\n        HTTPHandler(session, scheme="https"),  # https\n        WBArtifactHandler(),  # artifact\n        WBLocalArtifactHandler(),  # local_artifact\n        LocalFileHandler(),  # file_handler\n    ]\n',
            'wandb/sdk/artifacts/storage_policies/_multipart.py': '"""Helpers and constants for multipart upload and download."""\n\nfrom __future__ import annotations\n\nimport logging\nimport math\nimport threading\nfrom concurrent.futures import FIRST_EXCEPTION, Executor, wait\nfrom dataclasses import dataclass, field\nfrom queue import Queue\nfrom typing import TYPE_CHECKING, Any, Final, Iterator, Union\n\nfrom typing_extensions import TypeAlias, TypeIs, final\n\nfrom wandb import env\nfrom wandb.sdk.artifacts.artifact_file_cache import Opener\n\nif TYPE_CHECKING:\n    from requests import Session\n\nlogger = logging.getLogger(__name__)\n\nKiB: Final[int] = 1024\nMiB: Final[int] = 1024**2\nGiB: Final[int] = 1024**3\nTiB: Final[int] = 1024**4\n\n# AWS S3 max upload parts without having to make additional requests for extra parts\nMAX_PARTS = 1_000\nMIN_MULTI_UPLOAD_SIZE = 2 * GiB\nMAX_MULTI_UPLOAD_SIZE = 5 * TiB\n\n# Minimum size to switch to multipart download, same threshold as upload.\nMIN_MULTI_DOWNLOAD_SIZE = MIN_MULTI_UPLOAD_SIZE\n\n# Multipart download part size matches the upload size and is hard coded to\n# 100 MB.\n# https://github.com/wandb/wandb/blob/7b2a13cb8efcd553317167b823c8e52d8c3f7c4e/core/pkg/artifacts/saver.go#L496\n# https://docs.aws.amazon.com/AmazonS3/latest/userguide/optimizing-performance-guidelines.html#optimizing-performance-guidelines-get-range\nMULTI_DEFAULT_PART_SIZE = 100 * MiB\n\n# Chunk size for reading http response and writing to disk.\nRSP_CHUNK_SIZE = 1 * MiB\n\n\n@final\nclass _ChunkSentinel:\n    """Signal the end of the multipart chunk queue.\n\n    Queue consumers terminate when they receive this item from the queue. Do\n    not instantiate this class directly; use the `END_CHUNK` constant as a\n    pseudo-singleton instead.\n\n    NOTE: Use this only in multi-threaded (not multi-process) contexts because\n    it is not guaranteed to be process-safe.\n    """\n\n    def __repr__(self) -> str:\n        return "ChunkSentinel"\n\n\nEND_CHUNK: Final[_ChunkSentinel] = _ChunkSentinel()\n\n\ndef is_end_chunk(obj: Any) -> TypeIs[_ChunkSentinel]:\n    """Returns True if the object is the terminal queue item for multipart downloads."""\n    # Needed for type checking, since _ChunkSentinel isn\'t formally a singleton.\n    return obj is END_CHUNK\n\n\n@dataclass(frozen=True)\nclass ChunkContent:\n    __slots__ = ("offset", "data")  # slots=True only introduced in Python 3.10\n    offset: int\n    data: bytes\n\n\nQueuedChunk: TypeAlias = Union[ChunkContent, _ChunkSentinel]\n\n\ndef should_multipart_download(size: int | None, override: bool | None = None) -> bool:\n    return ((size or 0) >= MIN_MULTI_DOWNLOAD_SIZE) if (override is None) else override\n\n\ndef calc_part_size(file_size: int, min_part_size: int = MULTI_DEFAULT_PART_SIZE) -> int:\n    # Default to a chunk size of 100MiB. S3 has a cap of 10,000 upload parts.\n    return max(math.ceil(file_size / MAX_PARTS), min_part_size)\n\n\ndef scan_chunks(path: str, chunk_size: int) -> Iterator[bytes]:\n    with open(path, "rb") as f:\n        while data := f.read(chunk_size):\n            yield data\n\n\n@dataclass\nclass MultipartDownloadContext:\n    q: Queue[QueuedChunk]\n    cancel: threading.Event = field(default_factory=threading.Event)\n\n\ndef multipart_download(\n    executor: Executor,\n    session: Session,\n    url: str,\n    size: int,\n    cached_open: Opener,\n    part_size: int = MULTI_DEFAULT_PART_SIZE,\n):\n    """Download file as multiple parts in parallel.\n\n    Only one thread for writing to file. Each part run one http request in one thread.\n    HTTP response chunk of a file part is sent to the writer thread via a queue.\n    """\n    # ------------------------------------------------------------------------------\n    # Shared between threads\n    ctx = MultipartDownloadContext(q=Queue(maxsize=500))\n\n    # Put cache_open at top so we remove the tmp file when there is network error.\n    with cached_open("wb") as f:\n\n        def download_chunk(start: int, end: int | None = None) -> None:\n            # Error from another thread, no need to start\n            if ctx.cancel.is_set():\n                return\n\n            # https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers/Range\n            # Start and end are both inclusive. An empty end uses the actual end\n            # of the file. Example string: "bytes=0-499".\n            bytes_range = f"{start}-" if (end is None) else f"{start}-{end}"\n            headers = {"Range": f"bytes={bytes_range}"}\n            with session.get(url=url, headers=headers, stream=True) as rsp:\n                offset = start\n                for chunk in rsp.iter_content(chunk_size=RSP_CHUNK_SIZE):\n                    if ctx.cancel.is_set():\n                        return\n                    ctx.q.put(ChunkContent(offset=offset, data=chunk))\n                    offset += len(chunk)\n\n        def write_chunks() -> None:\n            # If all chunks are written or there\'s an error in another thread, shutdown\n            while not (ctx.cancel.is_set() or is_end_chunk(chunk := ctx.q.get())):\n                try:\n                    # NOTE: Seek works without pre allocating the file on disk.\n                    # It automatically creates a sparse file, e.g. ls -hl would show\n                    # a bigger size compared to du -sh * because downloading different\n                    # chunks is not a sequential write.\n                    # See https://man7.org/linux/man-pages/man2/lseek.2.html\n                    f.seek(chunk.offset)\n                    f.write(chunk.data)\n\n                except Exception as e:\n                    if env.is_debug():\n                        logger.debug(f"Error writing chunk to file: {e}")\n                    ctx.cancel.set()\n                    raise\n\n        # Start writer thread first.\n        write_future = executor.submit(write_chunks)\n\n        # Start download threads for each chunk.\n        download_futures = set()\n        for start in range(0, size, part_size):\n            # https://developer.mozilla.org/en-US/docs/Web/HTTP/Reference/Headers/Range\n            # Start and end are both inclusive. An empty end uses the actual end\n            # of the file. Example string: "bytes=0-499".\n            end = end if (end := (start + part_size - 1)) < size else None\n            download_futures.add(executor.submit(download_chunk, start=start, end=end))\n\n        # Wait for download\n        done, not_done = wait(download_futures, return_when=FIRST_EXCEPTION)\n        try:\n            for fut in done:\n                fut.result()\n        except Exception as e:\n            if env.is_debug():\n                logger.debug(f"Error downloading file: {e}")\n            ctx.cancel.set()\n\n            # Cancel any pending futures.  Note:\n            # - `Future.cancel()` does NOT stop the future if it\'s running, which is why\n            #   there\'s a separate `threading.Event` to ensure cooperative cancellation.\n            # - Once Python 3.8 support is dropped, replace these `fut.cancel()`\n            #   calls with `Executor.shutdown(cancel_futures=True)`.\n            for fut in not_done:\n                fut.cancel()\n            raise\n        finally:\n            # Always signal the writer to stop\n            ctx.q.put(END_CHUNK)\n            write_future.result()\n',
            'wandb/sdk/artifacts/storage_policies/wandb_storage_policy.py': '"""WandB storage policy."""\n\nfrom __future__ import annotations\n\nimport concurrent.futures\nimport hashlib\nimport logging\nimport os\nimport shutil\nfrom collections import deque\nfrom operator import itemgetter\nfrom typing import TYPE_CHECKING, Any\nfrom urllib.parse import quote\n\nfrom typing_extensions import assert_never\n\nfrom wandb.errors.term import termwarn\nfrom wandb.proto import wandb_internal_pb2 as pb\nfrom wandb.sdk.artifacts._gqlutils import server_supports\nfrom wandb.sdk.artifacts._models.storage import StoragePolicyConfig\nfrom wandb.sdk.artifacts.artifact_file_cache import (\n    ArtifactFileCache,\n    get_artifact_file_cache,\n)\nfrom wandb.sdk.artifacts.staging import get_staging_dir\nfrom wandb.sdk.artifacts.storage_handlers.multi_handler import MultiHandler\nfrom wandb.sdk.artifacts.storage_handlers.tracking_handler import TrackingHandler\nfrom wandb.sdk.artifacts.storage_layout import StorageLayout\nfrom wandb.sdk.artifacts.storage_policies._multipart import (\n    MAX_MULTI_UPLOAD_SIZE,\n    MIN_MULTI_UPLOAD_SIZE,\n    KiB,\n    calc_part_size,\n    multipart_download,\n    scan_chunks,\n)\nfrom wandb.sdk.artifacts.storage_policies.register import WANDB_STORAGE_POLICY\nfrom wandb.sdk.artifacts.storage_policy import StoragePolicy\nfrom wandb.sdk.internal.internal_api import Api as InternalApi\nfrom wandb.sdk.lib.hashutil import b64_to_hex_id, hex_to_b64_id\nfrom wandb.sdk.lib.paths import FilePathStr, URIStr\n\nfrom ._factories import make_http_session, make_storage_handlers\n\nif TYPE_CHECKING:\n    import requests\n\n    from wandb.filesync.step_prepare import StepPrepare\n    from wandb.sdk.artifacts.artifact import Artifact\n    from wandb.sdk.artifacts.artifact_manifest_entry import ArtifactManifestEntry\n    from wandb.sdk.internal import progress\n\nlogger = logging.getLogger(__name__)\n\n\nclass WandbStoragePolicy(StoragePolicy):\n    @classmethod\n    def name(cls) -> str:\n        return WANDB_STORAGE_POLICY\n\n    @classmethod\n    def from_config(cls, config: StoragePolicyConfig) -> WandbStoragePolicy:\n        return cls(config=config)\n\n    def __init__(\n        self,\n        config: StoragePolicyConfig | None = None,\n        cache: ArtifactFileCache | None = None,\n        api: InternalApi | None = None,\n    ) -> None:\n        self._config = StoragePolicyConfig.model_validate(config or {})\n\n        # Don\'t instantiate these right away if missing, instead defer to the\n        # first time they\'re needed. Otherwise, at the time of writing, this\n        # significantly slows down `Artifact.__init__()`.\n        self._maybe_cache = cache\n        self._maybe_api = api\n        self._maybe_session: requests.Session | None = None\n        self._maybe_handler: MultiHandler | None = None\n\n    @property\n    def _cache(self) -> ArtifactFileCache:\n        if self._maybe_cache is None:\n            self._maybe_cache = get_artifact_file_cache()\n        return self._maybe_cache\n\n    @property\n    def _api(self) -> InternalApi:\n        if self._maybe_api is None:\n            self._maybe_api = InternalApi()\n        return self._maybe_api\n\n    @_api.setter\n    def _api(self, api: InternalApi) -> None:\n        self._maybe_api = api\n\n    @property\n    def _session(self) -> requests.Session:\n        if self._maybe_session is None:\n            self._maybe_session = make_http_session()\n        return self._maybe_session\n\n    @property\n    def _handler(self) -> MultiHandler:\n        if self._maybe_handler is None:\n            self._maybe_handler = MultiHandler(\n                handlers=make_storage_handlers(self._session),\n                default_handler=TrackingHandler(),\n            )\n        return self._maybe_handler\n\n    def config(self) -> dict[str, Any]:\n        return self._config.model_dump(exclude_none=True)\n\n    def load_file(\n        self,\n        artifact: Artifact,\n        manifest_entry: ArtifactManifestEntry,\n        dest_path: str | None = None,\n        # FIXME: We should avoid passing the executor into multiple inner functions,\n        # it leads to confusing code and opaque tracebacks/call stacks.\n        executor: concurrent.futures.Executor | None = None,\n    ) -> FilePathStr:\n        """Use cache or download the file using signed url.\n\n        Args:\n            executor: A thread pool provided by the caller for multi-file\n                downloads. Reuse the thread pool for multipart downloads; it is\n                closed when the artifact download completes. If this is `None`,\n                download the file serially.\n        """\n        if dest_path is not None:\n            self._cache._override_cache_path = dest_path\n\n        path, hit, cache_open = self._cache.check_md5_obj_path(\n            manifest_entry.digest,\n            size=manifest_entry.size or 0,\n        )\n        if hit:\n            return path\n\n        if url := manifest_entry._download_url:\n            # Use multipart parallel download for large file\n            if executor and (size := manifest_entry.size):\n                multipart_download(executor, self._session, url, size, cache_open)\n                return path\n\n            # Serial download\n            try:\n                response = self._session.get(url, stream=True)\n            except requests.HTTPError:\n                # Signed URL might have expired, fall back to fetching it one by one.\n                manifest_entry._download_url = None\n\n        if manifest_entry._download_url is None:\n            auth = None\n            headers: dict[str, str] = {}\n\n            # For auth, prefer using (in order): auth header, cookies, HTTP Basic Auth\n            if token := self._api.access_token:\n                headers = {"Authorization": f"Bearer {token}"}\n            else:\n                auth = ("api", self._api.api_key or "")\n\n            file_url = self._file_url(artifact, manifest_entry)\n            response = self._session.get(\n                file_url,\n                auth=auth,\n                headers=headers,\n                stream=True,\n            )\n\n        with cache_open(mode="wb") as file:\n            for data in response.iter_content(chunk_size=16 * KiB):\n                file.write(data)\n        return path\n\n    def store_reference(\n        self,\n        artifact: Artifact,\n        path: URIStr | FilePathStr,\n        name: str | None = None,\n        checksum: bool = True,\n        max_objects: int | None = None,\n    ) -> list[ArtifactManifestEntry]:\n        return self._handler.store_path(\n            artifact, path, name=name, checksum=checksum, max_objects=max_objects\n        )\n\n    def load_reference(\n        self,\n        manifest_entry: ArtifactManifestEntry,\n        local: bool = False,\n        dest_path: str | None = None,\n    ) -> FilePathStr | URIStr:\n        assert manifest_entry.ref is not None\n        used_handler = self._handler._get_handler(manifest_entry.ref)\n        if hasattr(used_handler, "_cache") and (dest_path is not None):\n            used_handler._cache._override_cache_path = dest_path\n        return self._handler.load_path(manifest_entry, local)\n\n    def _file_url(self, artifact: Artifact, entry: ArtifactManifestEntry) -> str:\n        api = self._api\n        base_url: str = api.settings("base_url")\n\n        layout = self._config.storage_layout or StorageLayout.V1\n        region = self._config.storage_region or "default"\n\n        entity = artifact.entity\n        project = artifact.project\n        collection = artifact.name.split(":")[0]\n\n        hexhash = b64_to_hex_id(entry.digest)\n\n        if layout is StorageLayout.V1:\n            return f"{base_url}/artifacts/{entity}/{hexhash}"\n\n        if layout is StorageLayout.V2:\n            birth_artifact_id = entry.birth_artifact_id or ""\n            if server_supports(\n                api.client, pb.ARTIFACT_COLLECTION_MEMBERSHIP_FILE_DOWNLOAD_HANDLER\n            ):\n                return f"{base_url}/artifactsV2/{region}/{quote(entity)}/{quote(project)}/{quote(collection)}/{quote(birth_artifact_id)}/{hexhash}/{entry.path.name}"\n\n            return f"{base_url}/artifactsV2/{region}/{quote(entity)}/{quote(birth_artifact_id)}/{hexhash}"\n\n        assert_never(layout)\n\n    def s3_multipart_file_upload(\n        self,\n        file_path: str,\n        chunk_size: int,\n        hex_digests: dict[int, str],\n        multipart_urls: dict[int, str],\n        extra_headers: dict[str, str],\n    ) -> list[dict[str, Any]]:\n        etags: deque[dict[str, Any]] = deque()\n        file_chunks = scan_chunks(file_path, chunk_size)\n        for num, data in enumerate(file_chunks, start=1):\n            rsp = self._api.upload_multipart_file_chunk_retry(\n                multipart_urls[num],\n                data,\n                extra_headers={\n                    "content-md5": hex_to_b64_id(hex_digests[num]),\n                    "content-length": str(len(data)),\n                    "content-type": extra_headers.get("Content-Type") or "",\n                },\n            )\n            assert rsp is not None\n            etags.append({"partNumber": num, "hexMD5": rsp.headers["ETag"]})\n        return list(etags)\n\n    def default_file_upload(\n        self,\n        upload_url: str,\n        file_path: str,\n        extra_headers: dict[str, Any],\n        progress_callback: progress.ProgressFn | None = None,\n    ) -> None:\n        """Upload a file to the artifact store and write to cache."""\n        with open(file_path, "rb") as file:\n            # This fails if we don\'t send the first byte before the signed URL expires.\n            self._api.upload_file_retry(\n                upload_url, file, progress_callback, extra_headers=extra_headers\n            )\n\n    def store_file(\n        self,\n        artifact_id: str,\n        artifact_manifest_id: str,\n        entry: ArtifactManifestEntry,\n        preparer: StepPrepare,\n        progress_callback: progress.ProgressFn | None = None,\n    ) -> bool:\n        """Upload a file to the artifact store.\n\n        Returns:\n            True if the file was a duplicate (did not need to be uploaded),\n            False if it needed to be uploaded or was a reference (nothing to dedupe).\n        """\n        file_size = entry.size or 0\n        chunk_size = calc_part_size(file_size)\n        file_path = entry.local_path or ""\n        # Logic for AWS s3 multipart upload.\n        # Only chunk files if larger than 2 GiB. Currently can only support up to 5TiB.\n        if MIN_MULTI_UPLOAD_SIZE <= file_size <= MAX_MULTI_UPLOAD_SIZE:\n            file_chunks = scan_chunks(file_path, chunk_size)\n            upload_parts = [\n                {"partNumber": num, "hexMD5": hashlib.md5(data).hexdigest()}\n                for num, data in enumerate(file_chunks, start=1)\n            ]\n            hex_digests = dict(map(itemgetter("partNumber", "hexMD5"), upload_parts))\n        else:\n            upload_parts = []\n            hex_digests = {}\n\n        resp = preparer.prepare(\n            {\n                "artifactID": artifact_id,\n                "artifactManifestID": artifact_manifest_id,\n                "name": entry.path,\n                "md5": entry.digest,\n                "uploadPartsInput": upload_parts,\n            }\n        ).get()\n\n        entry.birth_artifact_id = resp.birth_artifact_id\n\n        if resp.upload_url is None:\n            return True\n        if entry.local_path is None:\n            return False\n\n        extra_headers = dict(hdr.split(":", 1) for hdr in (resp.upload_headers or []))\n\n        # This multipart upload isn\'t available, do a regular single url upload\n        if (multipart_urls := resp.multipart_upload_urls) is None and resp.upload_url:\n            self.default_file_upload(\n                resp.upload_url, file_path, extra_headers, progress_callback\n            )\n        elif multipart_urls is None:\n            raise ValueError(f"No multipart urls to upload for file: {file_path}")\n        else:\n            # Upload files using s3 multipart upload urls\n            etags = self.s3_multipart_file_upload(\n                file_path,\n                chunk_size,\n                hex_digests,\n                multipart_urls,\n                extra_headers,\n            )\n            assert resp.storage_path is not None\n            self._api.complete_multipart_upload_artifact(\n                artifact_id, resp.storage_path, etags, resp.upload_id\n            )\n        self._write_cache(entry)\n\n        return False\n\n    def _write_cache(self, entry: ArtifactManifestEntry) -> None:\n        if entry.local_path is None:\n            return\n\n        # Cache upon successful upload.\n        _, hit, cache_open = self._cache.check_md5_obj_path(\n            entry.digest,\n            size=entry.size or 0,\n        )\n\n        staging_dir = get_staging_dir()\n        try:\n            if not (entry.skip_cache or hit):\n                with cache_open("wb") as f, open(entry.local_path, "rb") as src:\n                    shutil.copyfileobj(src, f)\n            if entry.local_path.startswith(staging_dir):\n                # Delete staged files here instead of waiting till\n                # all the files are uploaded\n                os.chmod(entry.local_path, 0o600)\n                os.remove(entry.local_path)\n        except OSError as e:\n            termwarn(f"Failed to cache {entry.local_path}, ignoring {e}")\n',
        }
